/* ─── ANIMATED COUNTER ─── */
function AnimatedCounter({ target, suffix, isVisible }) {
  const [count, setCount] = useState(0);
  useEffect(() => {
    if (!isVisible) return;
    let start = 0;
    const duration = 2000;
    const step = (timestamp) => {
      if (!start) start = timestamp;
      const progress = Math.min((timestamp - start) / duration, 1);
      const eased = 1 - Math.pow(1 - progress, 3);
      setCount(Math.floor(eased * target));
      if (progress < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  }, [isVisible, target]);
  return <>{count}{suffix}</>;
}

/* ─── INTERACTIVE 3D GLOBE WITH REAL COUNTRIES ─── */
function WorldMap({ activeOffice, setActiveOffice }) {
  const [rotation, setRotation] = useState(0);
  const [hoveredOffice, setHoveredOffice] = useState(null);
  const [geoData, setGeoData] = useState(null);
  const [loaded, setLoaded] = useState(false);
  const animRef = useRef();
  const R = 190, CX = 250, CY = 250;

  // Load real TopoJSON and decode to GeoJSON
  useEffect(() => {
    fetch("https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json")
      .then((r) => r.json())
      .then((topo) => {
        const geoms = topo.objects.countries.geometries;
        const arcs = topo.arcs;
        const tr = topo.transform;

        function decodeArc(idx) {
          const rev = idx < 0;
          const arc = arcs[rev ? ~idx : idx];
          const pts = [];
          let x = 0, y = 0;
          for (const [dx, dy] of arc) {
            x += dx; y += dy;
            pts.push([x * tr.scale[0] + tr.translate[0], y * tr.scale[1] + tr.translate[1]]);
          }
          return rev ? pts.reverse() : pts;
        }
        function decodeRing(ring) {
          const c = [];
          for (const ai of ring) {
            const d = decodeArc(ai);
            c.push(...(c.length ? d.slice(1) : d));
          }
          return c;
        }
        const features = geoms.map((g) => {
          let coords;
          if (g.type === "Polygon") coords = g.arcs.map(decodeRing);
          else if (g.type === "MultiPolygon") coords = g.arcs.map((p) => p.map(decodeRing));
          return { type: g.type, coords };
        });
        setGeoData(features);
        setTimeout(() => setLoaded(true), 100);
      })
      .catch(() => setLoaded(true));
  }, []);

  // Auto-rotate
  useEffect(() => {
    const animate = () => {
      if (!hoveredOffice && activeOffice === null) {
        setRotation((r) => (r + 0.12) % 360);
      }
      animRef.current = requestAnimationFrame(animate);
    };
    animRef.current = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(animRef.current);
  }, [hoveredOffice, activeOffice]);

  // Orthographic projection onto sphere
  const project = useCallback((lng, lat) => {
    const lam = ((lng + rotation) * Math.PI) / 180;
    const phi = (lat * Math.PI) / 180;
    const x = CX + R * Math.cos(phi) * Math.sin(lam);
    const y = CY - R * Math.sin(phi);
    const z = Math.cos(phi) * Math.cos(lam);
    return { x, y, z, visible: z > -0.05 };
  }, [rotation]);

  // Build SVG path for a ring of coordinates on the sphere
  const ringPath = useCallback((coords) => {
    let d = "";
    let lastVisible = false;
    for (let i = 0; i < coords.length; i++) {
      const p = project(coords[i][0], coords[i][1]);
      if (p.visible) {
        d += (lastVisible ? "L" : "M") + p.x.toFixed(1) + "," + p.y.toFixed(1);
        lastVisible = true;
      } else {
        lastVisible = false;
      }
    }
    return d;
  }, [project]);

  // Build path for a full feature (Polygon or MultiPolygon)
  const featurePath = useCallback((feature) => {
    let d = "";
    if (feature.type === "Polygon") {
      for (const ring of feature.coords) d += ringPath(ring);
    } else if (feature.type === "MultiPolygon") {
      for (const polygon of feature.coords)
        for (const ring of polygon) d += ringPath(ring);
    }
    return d;
  }, [ringPath]);

  // Graticule
  const graticule = [];
  for (let lat = -60; lat <= 80; lat += 30) {
    let path = "";
    for (let lng = -180; lng <= 180; lng += 3) {
      const p = project(lng, lat);
      if (p.visible) path += (path ? "L" : "M") + p.x.toFixed(1) + "," + p.y.toFixed(1);
      else path += "";
    }
    if (path) graticule.push(path);
  }
  for (let lng = -180; lng < 180; lng += 30) {
    let path = "";
    for (let lat = -80; lat <= 80; lat += 3) {
      const p = project(lat, lng);
      // intentionally swap to get vertical lines — fix:
      const p2 = project(lng, lat);
      if (p2.visible) path += (path ? "L" : "M") + p2.x.toFixed(1) + "," + p2.y.toFixed(1);
    }
    if (path) graticule.push(path);
  }

  return (
    <div style={{ position: "relative" }}>
      <svg viewBox="0 0 500 500" style={{
        width: "100%", maxWidth: "500px",
        opacity: loaded ? 1 : 0, transition: "opacity 0.8s",
      }}>
        <defs>
          <radialGradient id="globe-bg" cx="38%" cy="32%">
            <stop offset="0%" stopColor="#2a2a2a" />
            <stop offset="100%" stopColor="#0e0e0e" />
          </radialGradient>
          <radialGradient id="globe-rim" cx="50%" cy="50%">
            <stop offset="85%" stopColor="transparent" />
            <stop offset="100%" stopColor="rgba(200,180,160,0.06)" />
          </radialGradient>
          <filter id="dot-glow">
            <feGaussianBlur stdDeviation="5" />
          </filter>
          <clipPath id="globe-clip">
            <circle cx={CX} cy={CY} r={R} />
          </clipPath>
        </defs>

        {/* Shadow */}
        <ellipse cx={CX} cy="465" rx="150" ry="18" fill="rgba(0,0,0,0.12)" />

        {/* Sphere */}
        <circle cx={CX} cy={CY} r={R} fill="url(#globe-bg)" stroke="rgba(200,180,160,0.12)" strokeWidth="0.8" />
        <circle cx={CX} cy={CY} r={R} fill="url(#globe-rim)" />

        <g clipPath="url(#globe-clip)">
          {/* Graticule */}
          {graticule.map((d, i) => (
            <path key={`gr-${i}`} d={d} fill="none" stroke="rgba(200,180,160,0.05)" strokeWidth="0.4" />
          ))}

          {/* Real countries */}
          {geoData && geoData.map((f, i) => {
            const d = featurePath(f);
            return d ? (
              <path
                key={`c-${i}`}
                d={d}
                fill="rgba(200,180,160,0.1)"
                stroke="rgba(200,180,160,0.2)"
                strokeWidth="0.4"
                strokeLinejoin="round"
              />
            ) : null;
          })}

          {/* Connection arcs between visible offices */}
          {offices.map((o1, i) =>
            offices.slice(i + 1).map((o2, j) => {
              const p1 = project(o1.lng, o1.lat);
              const p2 = project(o2.lng, o2.lat);
              if (p1.visible && p2.visible && p1.z > 0.1 && p2.z > 0.1) {
                const mx = (p1.x + p2.x) / 2;
                const my = (p1.y + p2.y) / 2 - 25;
                const isActive = activeOffice === i || activeOffice === (i + j + 1);
                return (
                  <path
                    key={`arc-${i}-${j}`}
                    d={`M${p1.x},${p1.y} Q${mx},${my} ${p2.x},${p2.y}`}
                    fill="none"
                    stroke={isActive ? "rgba(200,170,140,0.3)" : "rgba(200,170,140,0.07)"}
                    strokeWidth={isActive ? "1" : "0.5"}
                    strokeDasharray="3,5"
                  />
                );
              }
              return null;
            })
          )}

          {/* Office dots */}
          {offices.map((o, i) => {
            const p = project(o.lng, o.lat);
            if (!p.visible || p.z < 0) return null;
            const isActive = activeOffice === i || hoveredOffice === i;
            const opacity = Math.max(0.2, Math.min(1, p.z * 1.5));
            return (
              <g
                key={`off-${i}`}
                style={{ cursor: "pointer", opacity }}
                onMouseEnter={() => setHoveredOffice(i)}
                onMouseLeave={() => setHoveredOffice(null)}
                onClick={() => setActiveOffice(activeOffice === i ? null : i)}
              >
                {/* Pulse */}
                <circle cx={p.x} cy={p.y} r="10" fill="none" stroke="rgba(200,170,140,0.25)" strokeWidth="0.5">
                  <animate attributeName="r" values="6;16;6" dur="2.8s" repeatCount="indefinite" />
                  <animate attributeName="opacity" values="0.5;0;0.5" dur="2.8s" repeatCount="indefinite" />
                </circle>
                {/* Glow */}
                {isActive && (
                  <circle cx={p.x} cy={p.y} r="18" fill="rgba(200,170,140,0.1)" filter="url(#dot-glow)" />
                )}
                {/* Dot */}
                <circle
                  cx={p.x} cy={p.y}
                  r={isActive ? 5 : 3.5}
                  fill={isActive ? "#c8a882" : "#faf9f7"}
                  stroke={isActive ? "#c8a882" : "rgba(200,170,140,0.4)"}
                  strokeWidth="1"
                />
                {/* Label */}
                {isActive && (
                  <text
                    x={p.x} y={p.y - 14}
                    textAnchor="middle" fill="#faf9f7"
                    style={{
                      fontFamily: "'Manrope', sans-serif", fontSize: "10px",
                      fontWeight: 600, letterSpacing: "1.5px", textTransform: "uppercase",
                    }}
                  >
                    {o.city.toUpperCase()}
                  </text>
                )}
              </g>
            );
          })}
        </g>
      </svg>

      {/* Loading */}
      {!loaded && (
        <div style={{
          position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center",
        }}>
          <div style={{
            fontFamily: "'Manrope', sans-serif", fontSize: "11px", letterSpacing: "2px",
            textTransform: "uppercase", opacity: 0.3, color: "#faf9f7",
          }}>
            Loading globe...
          </div>
        </div>
      )}
    </div>
  );
}

/* ─── MAGNETIC CURSOR EFFECT ─── */
function MagneticButton({ children, className, onClick, style }) {
  const ref = useRef(null);
  const [pos, setPos] = useState({ x: 0, y: 0 });

  const handleMove = (e) => {
    if (!ref.current) return;
    const rect = ref.current.getBoundingClientRect();
    const x = (e.clientX - rect.left - rect.width / 2) * 0.2;
    const y = (e.clientY - rect.top - rect.height / 2) * 0.2;
    setPos({ x, y });
  };

  return (
    <button
      ref={ref}
      className={className}
      onClick={onClick}
      onMouseMove={handleMove}
      onMouseLeave={() => setPos({ x: 0, y: 0 })}
      style={{
        ...style,
        transform: `translate(${pos.x}px, ${pos.y}px)`,
        transition: "transform 0.25s cubic-bezier(0.25, 0.1, 0.25, 1), background 0.3s, color 0.3s",
      }}
    >
      {children}
    </button>
  );
}

/* ─── TEXT REVEAL COMPONENT ─── */
function RevealText({ children, isVisible, delay = 0 }) {
  return (
    <span style={{ display: "inline-block", overflow: "hidden" }}>
      <span
        style={{
          display: "inline-block",
          transform: isVisible ? "translateY(0)" : "translateY(110%)",
          transition: `transform 0.9s cubic-bezier(0.16, 1, 0.3, 1) ${delay}s`,
        }}
      >
        {children}
      </span>
    </span>
  );
}

/* ─── PARALLAX SECTION ─── */
function useParallax() {
  const [offset, setOffset] = useState(0);
  useEffect(() => {
    const handleScroll = () => setOffset(window.scrollY);
    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);
  return offset;
}

